#include <cstdio>
#include <cstdlib>
#include <ctime>
#include <omp.h>

#define INF 1000000

void floydWarshall(int *dist, int n) {
  for (int k = 0; k < n; ++k) {
#pragma omp target teams distribute parallel for map(tofrom: dist[0:n*n])
    for (int i = 0; i < n; ++i) {
      for (int j = 0; j < n; ++j) {
        int ij = i * n + j;
        int ik = i * n + k;
        int kj = k * n + j;
        if (dist[ik] + dist[kj] < dist[ij]) {
          dist[ij] = dist[ik] + dist[kj];
        }
      }
    }
  }
}

int main(int argc, char **argv) {
  if (argc != 2) {
    printf("Usage: %s <matrix dimension>\n", argv[0]);
    return 1;
  }
  int n = atoi(argv[1]);

  int *dist = (int *)malloc(n * n * sizeof(int));
  if (!dist) {
    fprintf(stderr, "Memory allocation failed\n");
    return 1;
  }

  srand(0);
  // Initialize the distance matrix
  for (int i = 0; i < n; ++i) {
    for (int j = 0; j < n; ++j) {
      if (i == j)
        dist[i * n + j] = 0;
      else {
        int r = rand() % 10;
        dist[i * n + j] = (r == 0) ? INF : r;
      }
    }
  }

  double start = omp_get_wtime();
#pragma omp target data map(tofrom: dist[0:n*n])
  {
    floydWarshall(dist, n);
  }
  double end = omp_get_wtime();

  printf("Execution time: %f sec\n", end - start);

  // Optionally print result for verification (commented out for large n)
  /*
  for (int i = 0; i < n; ++i) {
    for (int j = 0; j < n; ++j) {
      if (dist[i * n + j] == INF)
        printf("INF ");
      else
        printf("%d ", dist[i * n + j]);
    }
    printf("\n");
  }
  */

  free(dist);
  return 0;
}
